### 2. Drop-in patch (HyperIDE-WASM.html)
```js
/* ======= PR8 WASM engine (inline) ======= */
const pr8Runtime = `
let wasmModule = null;
let nativeCache = new Map();          // v8-style NativeModule cache

async function pr8Compile(bytes, importObject){
  const streaming = WebAssembly.compileStreaming
    ? await WebAssembly.compileStreaming(bytes)
    : await WebAssembly.compile(bytes);
  nativeCache.set(streaming, { weak_ptr: streaming, isolates: new Set() });
  return streaming;
}

async function pr8Instantiate(compiled, imports){
  return WebAssembly.instantiate(compiled, imports);
}

/* llama.cpp bridge */
async function initPR8(wasmUrl){
  const resp = await fetch(wasmUrl);
  const compiled = await pr8Compile(resp);
  const instance = await pr8Instantiate(compiled, {
    wasi_snapshot_preview1: {},
    env: { memory: new WebAssembly.Memory({initial: 256, maximum: 512}) }
  });
  return instance.exports;            // L = instance.exports
}
`;
```

---

### 3. Wire into your **existing** worker
Replace the **old initLlamaWasm()** inside **llama-worker.js** with:

```js
async function initLlamaWasm(){
  eval(pr8Runtime);                                    // inject PR8
  L = await initPR8('./llama.wasm');                   // same ABI you expect
  L.fs.mkdir('/models');
  send('ready', {backend: 'pr8'});
}
```

---

